const page=document.querySelector("body"),menu=page.querySelector(".main-nav__menu-list"),menuItem=menu.querySelectorAll(".main-nav__link"),menuBtn=page.querySelector(".main-nav__menu-button");menuBtn.onclick=function(){menu.classList.toggle("main-nav__menu-list--open")},menuItem.forEach((n=>{n.onclick=function(){menu.classList.remove("main-nav__menu-list--open")}}));